import{_ as e,o as r,c as a,ae as o}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Ads Analytics","description":"","frontmatter":{"title":"Ads Analytics","slug":"paid-ads-analytics"},"headers":[],"relativePath":"marketer-hub/paid-ads-analytics.md","filePath":"marketer-hub/paid-ads-analytics.md"}'),n={name:"marketer-hub/paid-ads-analytics.md"};function s(d,t,i,l,p,c){return r(),a("div",null,[...t[0]||(t[0]=[o('<div class="info custom-block"><p class="custom-block-title">Attention</p><p>Ads Analytics is part of the legacy Branch experience.</p><p>Our new Branch Analysis tool offers customizable dashboards made up of flexible widgets to capture the data you need. Branch Analysis is being rolled out to customers in phases. While you&#39;re waiting for access, discover how to filter, share, and export campaign performance across different channels on our <a href="https://help.branch.io/docs/branch-analysis" target="_blank" rel="noreferrer">Analysis Overview</a> page.</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Branch Ads Analytics Dashboard has two main sections: a high-level graph at the top and a detailed table below. Each view allows filtering and comparing in-app and web events by analytics parameters associated with your Branch Ad Links.</p><p>When creating a Branch Ad Link, you include a <strong>campaign</strong>, <strong>channel</strong>, and <strong>tags</strong>, and Branch will automatically add a <strong>feature</strong> and <strong>ad partner</strong> for filtering events.</p><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>Branch limits all dimensions to <strong>40,000 values per publisher per day</strong>. This means that you can only see up to 40,000 unique campaigns, ad names, etc. in the Branch Dashboard.</p><p>If an app tries to send more than 40,000 values for a single dimension (e.g. <code>~campaign</code>) in a day, then Branch stops tracking those unique values. Branch combines additional values together and bucket them under the value &quot;Other&quot;.</p></div><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>Adding <strong>ad partner</strong>, <strong>country</strong>, <strong>secondary publisher</strong>, and <strong>OS</strong> in the <strong>Compare by</strong> field will cause an error in loading data into the Events/Performance Table.</p></div><h2 id="dimensions" tabindex="-1">Dimensions <a class="header-anchor" href="#dimensions" aria-label="Permalink to &quot;Dimensions&quot;">​</a></h2><p>Branch integrates with many different ad partners, each with their own requirements and capabilities. Use this section to learn more about which dimensions are supported for which ad partner, and how to combine different dimensions in your reports.</p><h3 id="supported-san-dimensions" tabindex="-1">Supported SAN dimensions <a class="header-anchor" href="#supported-san-dimensions" aria-label="Permalink to &quot;Supported SAN dimensions&quot;">​</a></h3><p>Self-Attributing Networks (SANs) do not always support all of the dimensions available in your Branch analytics.</p><p>Please refer to the following table when using <strong>Compare by</strong> dimensions:</p><table tabindex="0"><thead><tr><th>Dimension</th><th>Facebook</th><th>Google</th><th>Apple Ads</th><th>Snap</th><th>Twitter</th></tr></thead><tbody><tr><td><strong>Feature</strong></td><td>Supported</td><td>Supported</td><td>Supported</td><td>Supported</td><td>Supported</td></tr><tr><td><strong>Channel</strong></td><td>Unsupported</td><td>Supported</td><td>Unsupported</td><td>Unsupported</td><td>Supported</td></tr><tr><td><strong>Campaign</strong></td><td>Supported</td><td>Supported</td><td>Supported</td><td>Supported</td><td>Supported</td></tr><tr><td><strong>Tags</strong></td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Supported</td></tr><tr><td><strong>Stage</strong></td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td></tr><tr><td><strong>Ad Partner</strong></td><td>Supported</td><td>Supported</td><td>Supported</td><td>Supported</td><td>Supported</td></tr><tr><td><strong>Secondary Publisher</strong></td><td>Supported</td><td>Supported</td><td>Unsupported</td><td>Unsupported</td><td>Supported</td></tr><tr><td><strong>Ad Set Name</strong></td><td>Supported</td><td>Unsupported</td><td>Supported</td><td>Supported</td><td>Unsupported</td></tr><tr><td><strong>Ad Name</strong></td><td>Supported</td><td>Unsupported</td><td>Unsupported</td><td>Supported</td><td>Unsupported</td></tr><tr><td><strong>Creative Name</strong></td><td>Supported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td></tr><tr><td><strong>Keyword</strong></td><td>Unsupported</td><td>Supported</td><td>Supported</td><td>Unsupported</td><td>Unsupported</td></tr><tr><td><strong>Last Touch Type</strong></td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Supported</td></tr><tr><td><strong>Link ID</strong></td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td></tr><tr><td><strong>Country</strong></td><td>Supported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Supported</td></tr><tr><td><strong>OS</strong></td><td>Unsupported</td><td>Unsupported</td><td>Supported</td><td>Unsupported</td><td>Supported</td></tr><tr><td><strong>Platform</strong></td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Supported</td></tr></tbody></table><h3 id="dimension-capabilities" tabindex="-1">Dimension capabilities <a class="header-anchor" href="#dimension-capabilities" aria-label="Permalink to &quot;Dimension capabilities&quot;">​</a></h3><p>Ad partner APIs often require Branch to make several sequential requests to retrieve all the data we surface to our customers.</p><p>Notably, <strong>not all dimensions are available for each request</strong>. Some are available in what we call “set A” and others are available in “set B”. Some are available in both, so they’re called “common”.</p><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>Sets A and B cannot be reconciled, so Branch defaults to set A if you select dimensions from both.</p></div><p>Branch’s <strong>recommendation</strong> when creating a report is to either:</p><ul><li>Use dimensions from set A, with any common dimensions you’d like <strong>or</strong></li><li>Use dimensions from set B, with any common dimensions you’d like</li></ul><p>That is, we advise <strong>not combining dimensions from sets A and B when creating a report</strong>.</p><p>For details on which dimensions are in sets A and B, and which dimensions are common, use the lists in these tabs:</p><h2 id="filter-bar" tabindex="-1">Filter bar <a class="header-anchor" href="#filter-bar" aria-label="Permalink to &quot;Filter bar&quot;">​</a></h2><p>At the top of the page, you&#39;ll see a menu of options that applies to both the graph and table views. With the filter bar, you can add attributes that will apply to both the graph and table views on this page.</p><p><em>[Image: Branch Dashboard Ads Analytics page displaying data options and filters for analysis and reporting.]</em></p><p>You can apply the following attributes:</p><table tabindex="0"><thead><tr><th>Attribute</th><th>Description</th></tr></thead><tbody><tr><td>Split SKAN data</td><td>When <strong>Split SKAN data</strong> is checked, your report will break your data into “non-SKAN”, “SKAN”, and “Total”. The total is the sum of non-SKAN and SKAN.</td></tr><tr><td>Organic</td><td>When <strong>Organic</strong> is checked, unattributed data will show (attributed: false). This data is not attributed to any click or impression, and is the same as &quot;organic&quot; or &quot;direct&quot; data.</td></tr><tr><td>Unique</td><td>When <strong>Unique</strong> is checked, these are unique to a user. For example: if 1 user clicks 100 times, it will count as 1. There is no concept of &quot;unique revenue&quot;; &quot;revenue&quot; is always the sum of all purchase events.</td></tr><tr><td>Dates</td><td>This is the date range for your report. By default, the Branch Dashboard will allow you to set the date range for up to <strong>6 months</strong> back.</td></tr><tr><td>Ad Partner</td><td>Apply the <strong>Ad Partner</strong> filter to your report to only display data from specific ad partners.</td></tr><tr><td>OS</td><td>Apply the <strong>OS</strong> filter to your report to only display data from specific operating systems.</td></tr><tr><td>Campaign</td><td>Apply the <strong>Campaign</strong> filter to your report to only display data from specific campaigns</td></tr><tr><td>Filters</td><td>Add additional filters that you apply to the report.</td></tr><tr><td>Reset</td><td>Reset the report back to a blank template</td></tr></tbody></table><h2 id="trends-graph" tabindex="-1">Trends graph <a class="header-anchor" href="#trends-graph" aria-label="Permalink to &quot;Trends graph&quot;">​</a></h2><p>Here you can see a visual breakdown of where your various in-app and web events are originating from. See the appendix for a breakdown of each event and filter type. These events can be further filtered by the various analytics tags from their originating ad campaigns.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><strong>Warning</strong><br> For iOS 14.5+, when the organic check-box is checked, the traffic being added to this view will include “true direct organic traffic <strong>plus</strong> misattributed first installs”.<br> This introduces <strong>double counting with the paid-attributed opted-in installs</strong> the page displays by default.</p><p>For additional information on changes <strong>post iOS 14.5</strong>, visit our <a href="https://help.branch.io/faq/docs/ios-14-faqs" target="_blank" rel="noreferrer">FAQ Pages</a></p></div><h2 id="events-table" tabindex="-1">Events table <a class="header-anchor" href="#events-table" aria-label="Permalink to &quot;Events table&quot;">​</a></h2><p>The Events table lets you see a more granular view of your event data. Here you can filter and compare fields while seeing a side-by-side view of your events.</p><h3 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h3><p>You can use the three-column button on the top right of the table to customize the columns viewable in the table. You can customize your columns even further through the Column Selector.</p><p>Events within each bucket are ordered by the volume received in the past 15 days. The most relevant events for each app will always appear at top of the list. You can also pin your favorite events and metrics to always appear on top.</p><p>Any event with zero volume will appear at the bottom irrespective of the event type.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>Below are the definitions for several percentage-related metrics:</p><ul><li><strong>Click to Install %</strong>: The percentage of attributed installs divided by clicks. Installs with &quot;last attributed touch type&quot; of value <code>IMPRESSION</code> are filtered out. Installs with &quot;platform&quot; of value <code>DESKTOP_WEB</code> and <code>DESKTOP_APP</code> are also filtered out.</li><li><strong>Click to Open %</strong>: The percentage of attributed opens divided by clicks. Opens with &quot;last attributed touch type&quot; of value <code>IMPRESSION</code> are filtered out. Opens with &quot;platform&quot; of value <code>DESKTOP_WEB</code> and <code>DESKTOP_APP</code> are also filtered out.</li></ul></div><h3 id="custom-metrics" tabindex="-1">Custom metrics <a class="header-anchor" href="#custom-metrics" aria-label="Permalink to &quot;Custom metrics&quot;">​</a></h3><p>In the column selector, you can also make your own custom metrics for more insights from your aggregated data. Formulaic calculations between event counts and aggregations are supported. Additionally, you will have access to templated calculations like <strong>Average Order Value</strong> and <strong>Customer Acquisition Cost</strong>.</p><p><em>[Image: 1500]</em></p><h2 id="drill-down-analytics" tabindex="-1">Drill-down analytics <a class="header-anchor" href="#drill-down-analytics" aria-label="Permalink to &quot;Drill-down analytics&quot;">​</a></h2><p>When you use the <strong>Compare by</strong> feature with multiple values, you will notice a <strong>plus icon</strong> appear in the rows of your table. Click the plus icon to expand these rows, which are separated by the different dimensions you provided.</p><p>In the example below, you can see ad partner, day, and platform are the chosen fields, and this is reflected in the <strong>Dimensions</strong> column of the table. The rows have been expanded, so you can see how each dimension is broken down.</p><h2 id="save-views" tabindex="-1">Save views <a class="header-anchor" href="#save-views" aria-label="Permalink to &quot;Save views&quot;">​</a></h2><p>The Branch Dashboard allows you to save the state of your report after you&#39;ve applied changes to your satisfaction. You can name and save your report for future use. This is helpful if you have several report types you use to analyze ads-related performance.</p><p><em>[Image: 1632]</em></p><h2 id="share-views" tabindex="-1">Share views <a class="header-anchor" href="#share-views" aria-label="Permalink to &quot;Share views&quot;">​</a></h2><p>Clicking the three-dot share button next to the name of your report will generate a shareable link to your report. Anyone with read access to your Branch Dashboard will be able to click the link and be directed to the report you created.</p><h2 id="revenue-and-cost" tabindex="-1">Revenue and cost <a class="header-anchor" href="#revenue-and-cost" aria-label="Permalink to &quot;Revenue and cost&quot;">​</a></h2><p>Unique to Branch Ads, the Branch Dashboard will enhance your analytics by adding cost-related parameters to your data. Through Branch&#39;s integration with specific ad partners, reports will be populated with the following analytics:</p><table tabindex="0"><thead><tr><th>Analytics Tag</th><th>Description</th><th>Used for</th></tr></thead><tbody><tr><td>Cost</td><td>Total cost (spend) for those dimensions (analytics tags, user data, time range), regardless of cost model</td><td>Understanding the total amount spent</td></tr><tr><td>Revenue</td><td>Revenue attributed to your selected filters</td><td>Calculating how much money you&#39;ve gained through commerce events</td></tr><tr><td>eCPI</td><td>cost / installs</td><td>Normalizing spend per install, to understand the average price of an install across networks or over time</td></tr><tr><td>eCPC</td><td>cost / clicks</td><td>Normalizing spend per click, to understand the average price of an click across networks or over time</td></tr><tr><td>eCPM</td><td>cost / (impressions / 1000)</td><td>Normalizing spend per thousand impressions, to understand the average price of 1000 impressions across networks or over time</td></tr><tr><td>eCPA</td><td>cost / purchases [includes web and app purchases]</td><td>Normalizing spend per purchase, to understand the average price of a purchase across networks or over time</td></tr><tr><td>Return On Investment (ROI)</td><td>(revenue-cost / cost) * 100</td><td>Deriving return on investment, to understand the percentage &quot;profit&quot; made on ad spend</td></tr><tr><td>Return On Ad Spend (ROAS)</td><td>(revenue / cost) * 100</td><td>Deriving return on investment by understanding the percentage revenue multiple for a given unit of spend</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Note</p><p>When looking at certain dimensions (ex. country), data may come in separately as <code>Unpopulated</code>. This is because different dimensions come from different forms in ingestion.</p><p>Metrics like Install and Cost are ingested by Branch from an ad partner, and it will have different dimensions.</p><p>Use <a href="./self-attributing-networks-sans.html#san-supported-analytics-parameters">this table</a> to see what parameters are supported by which SAN.</p></div><h3 id="local-currency" tabindex="-1">Local currency <a class="header-anchor" href="#local-currency" aria-label="Permalink to &quot;Local currency&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">Local Currency in Legacy vs New Branch</p><p>The instructions in this section outline setting local currency in the <a href="./branch-dashboard-overview.html">legacy Branch experience</a>.</p><p>For instructions on setting up local currency in the <a href="./new-branch-overview.html">new Branch experience</a>, please visit our documentation about the <a href="./general-page.html#local-currency">General</a> page.</p></div><p>By default, the Branch Dashboard <strong>will generate reports in USD</strong>. In order to view revenue and cost in your local currency, please enable the <strong>Local Currency</strong> setting in your Branch Dashboard&#39;s Configuration. Additional details can be found <a href="https://help.branch.io/v1/docs/advanced-settings-configuration#local-currency" target="_blank" rel="noreferrer">here</a>.</p><p>Local currency support in the Branch Dashboard will allow you to analyze marketing spend and revenue in your local currency. Additionally, it will allow for direct cost data comparison with ad partners who report their spending in a currency other than the USD.</p><p>With Local Currency enabled, you will gain new analytics tags as dimensions:</p><table tabindex="0"><thead><tr><th>Analytics Tag</th></tr></thead><tbody><tr><td>Cost in App Local Currency</td></tr><tr><td>Revenue in Local Currency</td></tr><tr><td>eCPA in Local Currency</td></tr><tr><td>eCPC in Local Currency</td></tr><tr><td>eCPI in Local Currency</td></tr><tr><td>eCPM in Local Currency</td></tr></tbody></table><h2 id="tips-and-tricks" tabindex="-1">Tips and tricks <a class="header-anchor" href="#tips-and-tricks" aria-label="Permalink to &quot;Tips and tricks&quot;">​</a></h2><ul><li><p>You can export your current table view as a CSV file using the download button on the top right of the table.</p></li><li><p>The <strong>Unique</strong> <strong>checkbox</strong> on both the graph and table views allows you to restrict reports to one event of each type per user. For example, take a user who clicked an ad link, then opened the app 7 times within the attribution window for that link. With the Unique box checked, we&#39;d report one of those opens, with it unchecked, we&#39;d report all 7.</p></li></ul>',58)])])}const g=e(n,[["render",s]]);export{h as __pageData,g as default};
